msg.url = 'http://docker-proxy:2375/containers/suricata-ids/exec';
msg.method = 'POST';
msg.headers = { 'Content-Type': 'application/json' };
// Using Tty:true prevents Docker from adding 8-byte multiplex headers!
msg.payload = {
    'AttachStdout': true,
    'Tty': true,
    'Cmd': ['tail', '-n', '15', '/var/log/suricata/eve.json']
};
return msg;

if (msg.payload && msg.payload.Id) {
    msg.url = 'http://docker-proxy:2375/exec/' + msg.payload.Id + '/start';
    msg.method = 'POST';
    msg.headers = { 'Content-Type': 'application/json' };
    // Tty:true guarantees a clean text response stream
    msg.payload = { 'Detach': false, 'Tty': true };
    return msg;
}

let raw = msg.payload || '';
let lines = raw.split('\n');
let alerts = [];

for (let i = 0; i < lines.length; i++) {
    let line = lines[i].trim();
    if (!line) continue;

    // Tty=true in exec ensures the text is clean, but let's be safe
    let jsonStart = line.indexOf('{"timestamp"');
    if (jsonStart !== -1) {
        try {
            let jsonStr = line.substring(jsonStart);
            let evt = JSON.parse(jsonStr);
            if (evt.event_type === 'alert') {
                let time = new Date(evt.timestamp).toLocaleTimeString();
                let sig = evt.alert.signature;
                let src = evt.src_ip + (evt.src_port ? ':' + evt.src_port : '');
                let dst = evt.dest_ip + (evt.dest_port ? ':' + evt.dest_port : '');
                alerts.push(`[${time}] 🚨 DETECTED: ${sig}\n    Target: ${src} -> ${dst}`);
            }
        } catch(e) {}
    }
}

alerts = alerts.reverse().slice(0, 15);

if (alerts.length === 0) {
    msg.payload = '🟢 System Secure: Watching for active threats in eve.json...';
} else {
    msg.payload = alerts.join('\n\n');
}

return msg;
